const handleInbound = async (req, res) => {
  try {
    const { items } = req.body;
    const userId = req.user?.id || req.body.user_id;

    if (!items || items.length === 0) {
      return res.status(400).json({ 
        success: false, 
        message: 'Danh sÃ¡ch sáº£n pháº©m trá»‘ng! Vui lÃ²ng thÃªm Ã­t nháº¥t 1 sáº£n pháº©m.' 
      });
    }

    // Validate tá»«ng item
    for (let item of items) {
      if (!item.productId || !item.quantity || item.quantity <= 0) {
        return res.status(400).json({
          success: false,
          message: 'Má»—i sáº£n pháº©m pháº£i cÃ³ productId vÃ  quantity > 0'
        });
      }
    }

    const result = await inboundService.createInboundReceipt(userId, items);

    res.json({
      success: true,
      message: `Nháº­p kho thÃ nh cÃ´ng! MÃ£ phiáº¿u: ${result.receiptCode}`,
      data: result
    });
  } catch (error) {
    console.error('Inbound Error:', error);
    res.status(500).json({ success: false, message: error.message });
  }
};

