const suggestBins = async (req, res) => {
  try {
    const { product_id, quantity } = req.body;

    if (!product_id) {
      return res.status(400).json({ success: false, message: 'Vui lÃ²ng chá»n sáº£n pháº©m' });
    }

    if (!quantity || quantity <= 0) {
      return res.status(400).json({ success: false, message: 'Sá»‘ lÆ°á»£ng pháº£i lá»›n hÆ¡n 0' });
    }

