const approveInbound = async (req, res) => {
  try {
    const receiptId = parseInt(req.params.id);
    const { action } = req.body; // 'approve' hoáº·c 'reject'

    if (!receiptId) {
      return res.status(400).json({ success: false, message: 'ID phiáº¿u nháº­p khÃ´ng há»£p lá»‡' });
    }

    if (!action || !['approve', 'reject'].includes(action)) {
      return res.status(400).json({ 
        success: false, 
        message: 'Action pháº£i lÃ  "approve" hoáº·c "reject"' 
      });
    }

    const result = await inboundService.approveReceipt(receiptId, action);

    res.json({
      success: true,
      message: result.message,
      data: result
    });
  } catch (error) {
    console.error('Approve Inbound Error:', error);
    res.status(500).json({ success: false, message: error.message });
  }
};

module.exports = {
  handleInbound,
  getInboundReceipts,
  getInboundReceiptById,
  suggestBins,
  getWarehouseOverview,
  approveInbound
};

