const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  ssl: {
    rejectUnauthorized: false // Báº¯t buá»™c khi dÃ¹ng Database trÃªn mÃ¢y
  }
});

pool.connect((err, client, release) => {
  if (err) {
    console.error('âŒ Lá»—i káº¿t ná»‘i Database:', err.stack);
  } else {
    console.log('âœ… ÄÃ£ káº¿t ná»‘i thÃ nh cÃ´ng vá»›i Database trÃªn ÄÃ¡m mÃ¢y!');
  }
