/**
 * TÃ¬m cÃ¡c Bin trá»‘ng trong Ä‘Ãºng Khu vá»±c (Zone)
 * Æ¯u tiÃªn xáº¿p: Táº§ng tháº¥p â†’ Táº§ng cao, Ká»‡ gáº§n â†’ Ká»‡ xa (theo lá»‘i Ä‘i xe nÃ¢ng)
 * Äá»‹nh dáº¡ng: TV-SN-A1-R1-S1-B1 (Zone-Aisle-Rack-Shelf-Bin)
 */
const getEmptyBinsByZone = async (zoneCode, neededQty) => {
  const result = await db.query(
    `SELECT id, location_code, aisle, rack, shelf, bin 
     FROM locations 
     WHERE zone_code = $1 AND status = 'EMPTY' 
     ORDER BY aisle ASC, rack ASC, shelf ASC, bin ASC 
     LIMIT $2`,
    [zoneCode, neededQty]
  );
  return result.rows;
};

/**
 * Láº¥y táº¥t cáº£ Bin trá»‘ng trong kho (Ä‘á»ƒ xem tá»•ng quan)
 */
const getAllEmptyBins = async () => {
  const result = await db.query(
    `SELECT id, location_code, zone_code, aisle, rack, shelf, bin 
     FROM locations 
     WHERE status = 'EMPTY' 
     ORDER BY zone_code, aisle, rack, shelf, bin`
  );
  return result.rows;
};

/**
 * Äáº¿m sá»‘ Bin trá»‘ng cÃ²n láº¡i trong má»—i khu vá»±c
 */
const getEmptyBinCountByZone = async () => {
  const result = await db.query(
    `SELECT zone_code, COUNT(*) as empty_count 
     FROM locations 
     WHERE status = 'EMPTY' 
     GROUP BY zone_code 
     ORDER BY zone_code`
  );
  return result.rows;
};

// ============================================
// QUáº¢N LÃ PHIáº¾U NHáº¬P KHO
// ============================================

/**
 * Táº¡o má»›i má»™t Phiáº¿u Nháº­p kho
 * Cáº¥u trÃºc báº£ng thá»±c táº¿: id, receipt_code, user_id, status, created_at
 */
const createInboundReceipt = async (receiptCode, userId) => {
  const result = await db.query(
    `INSERT INTO inbound_receipts (receipt_code, user_id, status, created_at) 
     VALUES ($1, $2, 'PENDING', NOW()) 
