const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const authModel = require('../models/authModel');

// Con dáº¥u xá»‹n cá»§a cÃ´ng ty Ä‘á»ƒ Ä‘Ã³ng má»™c lÃªn Tháº» tá»« (JWT)
// Thá»±c táº¿ ngÆ°á»i ta giáº¥u cÃ¡i nÃ y Ä‘i, nhÆ°ng mÃ¬nh Ä‘ang test nÃªn Ä‘á»ƒ Ä‘Ã¢y cho dá»…
const SECRET_KEY = 'DoAn_WMS_Secret_2026';

const registerUser = async (username, password, fullName, role) => {
  const existingUser = await authModel.getUserByUsername(username);
  if (existingUser) throw new Error('âŒ TÃªn Ä‘Äƒng nháº­p nÃ y Ä‘Ã£ cÃ³ ngÆ°á»i xÃ i!');

  // BÄƒm máº­t kháº©u ra 10 máº£nh
  const passwordHash = await bcrypt.hash(password, 10);

  // Tá»± sinh mÃ£ NhÃ¢n viÃªn y nhÆ° em lÃ m vá»›i khÃ¡ch hÃ ng
  const randomNum = Math.floor(1000 + Math.random() * 9000);
  const employeeCode = `NV-${randomNum}`;

  return await authModel.createUser(username, passwordHash, fullName, role, employeeCode);
};

const loginUser = async (username, password) => {
  const user = await authModel.getUserByUsername(username);
  if (!user) throw new Error('âŒ KhÃ´ng tÃ¬m tháº¥y tÃ i khoáº£n nÃ y!');

  // Láº¥y máº­t kháº©u nháº­p vÃ o so sÃ¡nh vá»›i má»› bÄƒm nÃ¡t trong Database
  const isMatch = await bcrypt.compare(password, user.password_hash);
  if (!isMatch) throw new Error('âŒ Sai máº­t kháº©u rá»“i em Æ¡i!');

  // ÄÄƒng nháº­p thÃ nh cÃ´ng -> In tháº» tá»« (Token) cÃ³ háº¡n dÃ¹ng 8 tiáº¿ng
  const token = jwt.sign(
    { id: user.id, role: user.role, name: user.full_name },
    SECRET_KEY,
    { expiresIn: '8h' }
  );

  return {
    token,
    user: {
      id: user.id,
      username: user.username,
      full_name: user.full_name, // Gá»­i Ä‘Ãºng chá»¯ full_name Ä‘á»ƒ Sidebar in ra
      role: user.role,
      level: user.level          // Gá»­i thÃªm level Ä‘á»ƒ Sidebar tá»± Ä‘á»•i mÃ u
    }
  };
};

module.exports = { registerUser, loginUser, SECRET_KEY };

