};

const scanItem = async (shipmentId, sku) => {
  const product = await factoryModel.getProductBySKU(sku);
  if (!product) throw new Error('âŒ MÃ£ váº¡ch tÃ o lao!');

  // Tá»· lá»‡ lá»—i 10% (0.1)
  const isDefective = Math.random() < 0.1; 

  if (isDefective) {
    // Náº¿u bá»‘c trÃºng hÃ ng lá»—i, chá»n ngáº«u nhiÃªn 1 lÃ½ do
    const reasons = ['MÃ³p mÃ©o vá» há»™p', 'Vá»¡ mÃ n hÃ¬nh', 'Thiáº¿u phá»¥ kiá»‡n', 'Báº­t khÃ´ng lÃªn nguá»“n'];
    const randomReason = reasons[Math.floor(Math.random() * reasons.length)];

    await factoryModel.recordDefectiveItem(shipmentId, product.id, randomReason);

    return {
      status: 'DEFECTIVE',
      productName: product.name,
      reason: randomReason
    };
  } else {
    // Náº¿u hÃ ng ngon (90%), thÃ¬ cá»™ng vÃ o sá»‘ hÃ ng tá»‘t (scanned_qty) nhÆ° cÅ©
    const updatedDetail = await factoryModel.updateScannedQuantity(shipmentId, product.id);

    // ðŸ‘‡ THÃŠM 3 DÃ’NG Báº¢O Vá»† NÃ€Y VÃ€O ðŸ‘‡
    if (!updatedDetail) {
      throw new Error('âŒ MÃ£ Lá»‡nh Giao HÃ ng (shipment_id) bá»‹ sai, hoáº·c sáº£n pháº©m nÃ y khÃ´ng cÃ³ trong Lá»‡nh!');
    }
    // ðŸ‘† THÃŠM XONG ðŸ‘†

    if (updatedDetail.scanned_qty > updatedDetail.expected_qty) {
      throw new Error(`âš ï¸ Cáº¢NH BÃO: QuÃ©t lá»‘ sá»‘ lÆ°á»£ng NhÃ  mÃ¡y bÃ¡o!`);
    }

    return {
      status: 'GOOD',
      productName: product.name,
      expected: updatedDetail.expected_qty,
      scanned: updatedDetail.scanned_qty
    };
  }
};



module.exports = { requestShipment, authorizeShipment, scanItem };

const inboundModel = require('../models/inboundModel');

// ============================================
// NGHIá»†P Vá»¤ Táº O PHIáº¾U NHáº¬P KHO
// ============================================

/**
 * Táº¡o phiáº¿u nháº­p kho má»›i
 * @param {number} userId - ID ngÆ°á»i táº¡o phiáº¿u
 * @param {Array} items - Danh sÃ¡ch sáº£n pháº©m: [{ productId, quantity }]
 * @returns {Object} ThÃ´ng tin phiáº¿u nháº­p
 */
const createInboundReceipt = async (userId, items) => {
  // BÆ°á»›c 1: Validate dá»¯ liá»‡u Ä‘áº§u vÃ o
  if (!items || items.length === 0) {
    throw new Error('Danh sÃ¡ch sáº£n pháº©m trá»‘ng!');
  }

  // BÆ°á»›c 2: Xá»­ lÃ½ tá»«ng sáº£n pháº©m - gá»£i Ã½ vá»‹ trÃ­
  const processedItems = [];

  for (let item of items) {
    // Láº¥y thÃ´ng tin sáº£n pháº©m
    const product = await inboundModel.getProductInfo(item.productId);
    if (!product) {
      throw new Error(`KhÃ´ng tÃ¬m tháº¥y sáº£n pháº©m ID ${item.productId}`);
    }

    // XÃ¡c Ä‘á»‹nh Zone dá»±a trÃªn category vÃ  brand
    const zoneCode = `${product.category_code}-${product.brand_code}`;

    // Tá»± Ä‘á»™ng gá»£i Ã½ cÃ¡c Bin trá»‘ng
    const emptyBins = await inboundModel.getEmptyBinsByZone(zoneCode, item.quantity);

    // Kiá»ƒm tra Ä‘á»§ vá»‹ trÃ­ khÃ´ng
    if (emptyBins.length < item.quantity) {
      const available = emptyBins.length;
      throw new Error(
        `Khu vá»±c "${zoneCode}" (${product.category_code === 'TV' ? 'Tivi' : 
          product.category_code === 'TL' ? 'Tá»§ láº¡nh' : 
          product.category_code === 'MG' ? 'MÃ¡y giáº·t' : 'MÃ¡y láº¡nh'} ${product.brand_code}) ` +
        `chá»‰ cÃ²n ${available} vá»‹ trÃ­ trá»‘ng, khÃ´ng Ä‘á»§ cho ${item.quantity} sáº£n pháº©m!`
      );
    }

    processedItems.push({
      productId: item.productId,
      quantity: item.quantity,
      suggestedBins: emptyBins,
      zoneCode: zoneCode,
      productName: product.name,
      sku: product.sku
    });
  }

  // BÆ°á»›c 3: Táº¡o mÃ£ phiáº¿u nháº­p tá»± Ä‘á»™ng
  const receiptCode = await inboundModel.generateReceiptCode();

  // BÆ°á»›c 4: Táº¡o phiáº¿u nháº­p trong database
  const receiptId = await inboundModel.createInboundReceipt(receiptCode, userId);

  // BÆ°á»›c 5: Xá»­ lÃ½ tá»«ng sáº£n pháº©m - lÆ°u chi tiáº¿t + cáº­p nháº­t inventory
  const receiptDetails = [];

  for (let item of processedItems) {
    for (let i = 0; i < item.quantity; i++) {
      const bin = item.suggestedBins[i];

      // LÆ°u chi tiáº¿t phiáº¿u nháº­p
      await inboundModel.addInboundDetail(receiptId, item.productId, bin.id, 1);

      // Cáº­p nháº­t tráº¡ng thÃ¡i Bin: ÄÃNH Dáº¤U Äáº¦Y
      await inboundModel.occupyBin(bin.id, item.productId, 1);

      // Cáº­p nháº­t tá»“n kho tá»•ng (warehouse_id = 1 lÃ  kho máº·c Ä‘á»‹nh)
      await inboundModel.updateInventory(item.productId, 1, 1);

      receiptDetails.push({
        sku: item.sku,
        productName: item.productName,
        locationCode: bin.location_code,
        quantity: 1,
        zoneCode: item.zoneCode
      });
    }
  }

  return {
    receiptId,
    receiptCode,
    totalProducts: items.reduce((sum, i) => sum + i.quantity, 0),
    totalItems: processedItems.length,
    details: receiptDetails,
    createdAt: new Date()
  };
};

// ============================================
// NGHIá»†P Vá»¤ Gá»¢I Ã Vá»Š TRÃ BIN
// ============================================

/**
 * Gá»£i Ã½ vá»‹ trÃ­ Bin trá»‘ng tá»‘i Æ°u cho má»™t sáº£n pháº©m
 * @param {number} productId - ID sáº£n pháº©m
 * @param {number} quantity - Sá»‘ lÆ°á»£ng cáº§n nháº­p
 * @returns {Object} ThÃ´ng tin gá»£i Ã½
 */
const suggestBinLocations = async (productId, quantity) => {
  const product = await inboundModel.getProductInfo(productId);
  if (!product) {
    throw new Error('KhÃ´ng tÃ¬m tháº¥y sáº£n pháº©m');
  }

  const zoneCode = `${product.category_code}-${product.brand_code}`;
  const emptyBins = await inboundModel.getEmptyBinsByZone(zoneCode, quantity);

  if (emptyBins.length < quantity) {
    return {
      success: false,
      message: `Khu vá»±c ${zoneCode} chá»‰ cÃ²n ${emptyBins.length} vá»‹ trÃ­ trá»‘ng`,
      available: emptyBins.length,
      suggestedBins: emptyBins,
      zoneCode
    };
  }

  return {
    success: true,
    productId,
    productName: product.name,
    sku: product.sku,
    zoneCode,
    zoneName: getZoneName(zoneCode),
    quantity,
    suggestedBins: emptyBins.slice(0, quantity),
    message: `Gá»£i Ã½ ${quantity} vá»‹ trÃ­ trong khu ${getZoneName(zoneCode)}`
  };
};

/**
 * Láº¥y tá»•ng quan tÃ¬nh tráº¡ng cÃ¡c khu vá»±c kho
 */
const getWarehouseOverview = async () => {
  const emptyBinCounts = await inboundModel.getEmptyBinCountByZone();

  // Äá»‹nh dáº¡ng káº¿t quáº£ theo category
  const overview = {
    TV: { name: 'Tivi', zones: {} },
    TL: { name: 'Tá»§ Láº¡nh', zones: {} },
    MG: { name: 'MÃ¡y Giáº·t', zones: {} },
    ML: { name: 'MÃ¡y Láº¡nh', zones: {} }
  };

  emptyBinCounts.forEach(row => {
    const [category, brand] = [row.zone_code.substring(0, 2), row.zone_code.substring(3)];
    if (overview[category]) {
      overview[category].zones[brand] = {
        zoneCode: row.zone_code,
        emptyCount: parseInt(row.empty_count),
        zoneName: getZoneName(row.zone_code)
      };
    }
  });

  return overview;
};

// ============================================
// NGHIá»†P Vá»¤ XEM & DUYá»†T PHIáº¾U NHáº¬P
// ============================================

/**
 * Láº¥y danh sÃ¡ch phiáº¿u nháº­p kho (cÃ³ phÃ¢n trang)
 */
const getInboundReceipts = async (page = 1, limit = 20) => {
  const offset = (page - 1) * limit;
  const receipts = await inboundModel.getAllInboundReceipts(limit, offset);
  const total = await inboundModel.countInboundReceipts();

  return {
    receipts,
    pagination: {
      page,
      limit,
      total,
      totalPages: Math.ceil(total / limit)
    }
  };
};

/**
 * Láº¥y chi tiáº¿t má»™t phiáº¿u nháº­p
 */
const getReceiptDetails = async (receiptId) => {
  const receipt = await inboundModel.getInboundReceiptById(receiptId);
  if (!receipt) {
    throw new Error('KhÃ´ng tÃ¬m tháº¥y phiáº¿u nháº­p');
  }

  const details = await inboundModel.getInboundReceiptDetails(receiptId);

  // NhÃ³m chi tiáº¿t theo Zone Ä‘á»ƒ hiá»ƒn thá»‹ Ä‘áº¹p hÆ¡n
  const groupedByZone = {};
  details.forEach(d => {
    if (!groupedByZone[d.zone_code]) {
      groupedByZone[d.zone_code] = {
        zoneCode: d.zone_code,
        zoneName: getZoneName(d.zone_code),
        items: [],
        totalQty: 0
      };
    }
    groupedByZone[d.zone_code].items.push(d);
    groupedByZone[d.zone_code].totalQty += d.quantity;
  });

  return {
    ...receipt,
    details,
    groupedByZone: Object.values(groupedByZone),
    totalProducts: details.reduce((sum, d) => sum + d.quantity, 0)
  };
};

/**
 * Duyá»‡t/Tá»« chá»‘i phiáº¿u nháº­p kho
 */
const approveReceipt = async (receiptId, action) => {
  const receipt = await inboundModel.getInboundReceiptById(receiptId);
  if (!receipt) {
    throw new Error('KhÃ´ng tÃ¬m tháº¥y phiáº¿u nháº­p');
  }

  if (receipt.status !== 'PENDING') {
    throw new Error(`Phiáº¿u Ä‘ang á»Ÿ tráº¡ng thÃ¡i "${receipt.status}", khÃ´ng thá»ƒ duyá»‡t!`);
  }

  const newStatus = action === 'approve' ? 'APPROVED' : 'REJECTED';
  await inboundModel.updateReceiptStatus(receiptId, newStatus);

  return {
    receiptId,
    receiptCode: receipt.receipt_code,
    newStatus,
    message: action === 'approve' 
      ? `ÄÃ£ duyá»‡t phiáº¿u ${receipt.receipt_code}` 
      : `ÄÃ£ tá»« chá»‘i phiáº¿u ${receipt.receipt_code}`
  };
};

// ============================================
// HÃ€M Há»– TRá»¢
// ============================================

/**
 * Chuyá»ƒn Zone Code thÃ nh tÃªn hiá»ƒn thá»‹
 */
const getZoneName = (zoneCode) => {
  const categoryNames = {
    'TV': 'Tivi',
    'TL': 'Tá»§ Láº¡nh',
    'MG': 'MÃ¡y Giáº·t',
    'ML': 'MÃ¡y Láº¡nh'
  };

  const brandNames = {
    'SN': 'Sony',
    'SS': 'Samsung',
    'LG': 'LG',
    'TC': 'TCL',
    'PNS': 'Panasonic',
    'AQ': 'Aqua',
    'TSB': 'Toshiba',
    'HTC': 'Hitachi',
    'EL': 'Electrolux',
    'DK': 'Daikin',
    'CP': 'Casper',
    'SP': 'Sharp'
  };

  const [cat, brand] = [zoneCode.substring(0, 2), zoneCode.substring(3)];
  return `${categoryNames[cat] || cat} ${brandNames[brand] || brand}`;
};

module.exports = {
  createInboundReceipt,
  suggestBinLocations,
  getWarehouseOverview,
  getInboundReceipts,
  getReceiptDetails,
  approveReceipt,
  getZoneName
};

