    const hash = await bcrypt.hash('123456', 10);
    // Update default password for all users
    await db.query("UPDATE users SET password_hash = $1", [hash]);
    res.send(`
âœ… Cáº­p nháº­t máº­t kháº©u há»‡ thá»‘ng thÃ nh cÃ´ng.
MÃ£ bÄƒm: ${hash}`);
  } catch (error) {
    res.status(500).send('âŒ Lá»—i há»‡ thá»‘ng: ' + error.message);
  }
});

app.post('/api/login', async (req, res) => {
  try {
    const { username, password } = req.body;

    const result = await db.query('SELECT * FROM users WHERE username = $1', [username]);
    if (result.rows.length === 0) {
      return res.status(401).json({ success: false, message: 'Sai tÃ i khoáº£n hoáº·c máº­t kháº©u!' });
    }

    const user = result.rows[0];

    const isMatch = await bcrypt.compare(password, user.password_hash);
    if (!isMatch) {
      return res.status(401).json({ success: false, message: 'Sai tÃ i khoáº£n hoáº·c máº­t kháº©u!' });
    }

    const token = jwt.sign(
      { id: user.id, username: user.username, role: user.role },
      process.env.JWT_SECRET || 'DoAn_WMS_Secret_2026',
      { expiresIn: '1d' }
    );

    res.json({
      success: true,
      message: 'ÄÄƒng nháº­p thÃ nh cÃ´ng!',
      token: token,
      user: {
        id: user.id,
        username: user.username,
        full_name: user.full_name,
        role: user.role,
        level: user.level
      }
    });

  } catch (error) {
    console.error('Login Error:', error);
    res.status(500).json({ success: false, message: 'Lá»—i mÃ¡y chá»§!' });
  }
});

// Start Server
